mapper.insert:
/** CmmtSurveyDao.insert */
insert into cmmt_survey (
	 survey_id
	,survey_nm
	,system_id
	,begin_day
	,end_day
	,remark
	,enabled
	,duplicated
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{surveyId}
	,#{surveyNm}
	,#{systemId}
	,#{beginDay}
	,#{endDay}
	,#{remark}
	,#{enabled}
	,#{duplicated}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.select:
/** CmmtSurveyDao.select */
select

from
	cmmt_survey
where
	survey_id = #{surveyId}

mapper.sql:
1=1

	and system_id = #{param.systemId}


	AND (
		begin_day between #{param.beginDay} and #{param.endDay}
		or end_day between #{param.beginDay} and #{param.endDay}
		or (
			begin_day < #{param.beginDay}
			and end_day > #{param.beginDay}
		)
	)



	and (
		enabled = false
		or begin_day > to_char(now(), 'yyyymmdd')
	)




	and (
		enabled = true
		and to_char(now(), 'yyyymmdd') between begin_day and end_day
	)




	and (
		end_day < to_char(now(), 'yyyymmdd')
	)



	and survey_nm like '%' || #{param.surveyNm} || '%'

mapper.delete:
/** CmmtSurveyDao.delete */
delete from
	cmmt_survey
where
	survey_id = #{surveyId}

mapper.update:
/** CmmtSurveyDao.update */
update cmmt_survey set
	 survey_nm  = #{surveyNm}
	,system_id  = #{systemId}
	,begin_day  = #{beginDay}
	,end_day    = #{endDay}
	,remark     = #{remark}
	,enabled    = #{enabled}
	,duplicated = #{duplicated}
	,creator_id = #{creatorId}
	,created_dt = #{createdDt}
	,updater_id = #{updaterId}
	,updated_dt = #{updatedDt}
where
	survey_id = #{surveyId}
